// DisCloud mode: dashboard dimatikan default agar bot Discord bisa stabil 24/7 tanpa web runtime.
// Aktifkan lagi nanti dengan DASHBOARD_ENABLED=true.
const isDashboardEnabled = String(process.env.DASHBOARD_ENABLED || "false").toLowerCase() === "true";


const dashboardSecret = process.env.DASHBOARD_SECRET || process.env.DISCORD_TOKEN || "pak-rw-dashboard-secret";
const dashboardPassword = process.env.DASHBOARD_PASSWORD || "desatulus";
const dashboardSessions = new Set();

function makeSessionToken() {
  return crypto.randomBytes(24).toString("hex");
}

function getCookie(req, name) {
  const raw = req.headers.cookie || "";
  const parts = raw.split(";").map((x) => x.trim());
  const found = parts.find((x) => x.startsWith(`${name}=`));
  return found ? decodeURIComponent(found.slice(name.length + 1)) : "";
}

function isDashboardAuth(req) {
  const token = getCookie(req, "pakrw_dashboard");
  return Boolean(token && dashboardSessions.has(token));
}

function requireDashboardAuth(req, res, next) {
  if (isDashboardAuth(req)) return next();
  return res.redirect("/login");
}

function getDashboardConfigPath() {
  const localConfigPath = path.join(__dirname, "config.json");

  const candidates = [
    process.env.PAK_RW_CONFIG_PATH,
    process.env.PAK_RW_DATA_DIR ? path.join(process.env.PAK_RW_DATA_DIR, "config.json") : null,
    process.env.DATA_DIR ? path.join(process.env.DATA_DIR, "config.json") : null,
    localConfigPath
  ].filter(Boolean);

  for (const filePath of candidates) {
    try {
      const dir = path.dirname(filePath);
      fs.mkdirSync(dir, { recursive: true });

      if (fs.existsSync(filePath)) return filePath;

      // Kalau pakai folder persistent /data tapi config belum ada,
      // copy config repo pertama kali supaya dashboard tetap punya isi awal.
      if (filePath !== localConfigPath && fs.existsSync(localConfigPath)) {
        fs.copyFileSync(localConfigPath, filePath);
        return filePath;
      }
    } catch {
      // Coba lokasi berikutnya
    }
  }

  return localConfigPath;
}

function readConfigFile() {
  try {
    const configPath = getDashboardConfigPath();
    return JSON.parse(fs.readFileSync(configPath, "utf8"));
  } catch (err) {
    console.log("READ CONFIG ERROR:", err.message);
    return {};
  }
}

function applySafeEmbedDisplayMigrations(data = {}) {
  const next = data && typeof data === "object" ? data : {};
  next.embeds = next.embeds && typeof next.embeds === "object" ? next.embeds : {};

  const profile = next.embeds.levelProfile = next.embeds.levelProfile && typeof next.embeds.levelProfile === "object"
    ? next.embeds.levelProfile
    : {};
  const oldProfileTitle = String(profile.title || "").trim();
  if (!oldProfileTitle || oldProfileTitle === "<a:loading:1490575251405406299> Data Keaktifan Warga" || oldProfileTitle === ":loading: Data Keaktifan Warga") {
    profile.title = "<a:bar_chart:1516453838117277829> Data Keaktifan Warga";
  }
  // Embed protected ini sengaja tanpa media agar tidak muncul label Image/thumbnail.
  profile.thumbnail = "";
  profile.image = "";

  const levelUp = next.embeds.levelUp = next.embeds.levelUp && typeof next.embeds.levelUp === "object"
    ? next.embeds.levelUp
    : {};
  levelUp.title = levelUp.title || "<a:rocket_animated:1512884173453529288> Warga Naik Level";
  levelUp.thumbnail = "";
  levelUp.image = "";
  levelUp.fields = Array.isArray(levelUp.fields) ? levelUp.fields : [];
  if (!levelUp.fields[0]) {
    levelUp.fields[0] = {
      name: "<a:Chart_Increasing:1516454160684290219> Menuju Level {nextLevel} ({nextRank})",
      value: "Butuh:\n**{remainingPoints} poin total lagi**\nChat: **{chat} poin**\nVoice: **{voice} poin**",
      inline: false
    };
  } else {
    const oldFieldName = String(levelUp.fields[0].name || "").trim();
    if (!oldFieldName || oldFieldName.startsWith("📈 Menuju Level")) {
      levelUp.fields[0].name = "<a:Chart_Increasing:1516454160684290219> Menuju Level {nextLevel} ({nextRank})";
    }
  }

  next.topActive = next.topActive && typeof next.topActive === "object" ? next.topActive : {};
  next.topActive.rowArrowEmoji = normalizePakRwEmojiCodes(
    next.topActive.rowArrowEmoji || "<a:Animated_Arrow_Bluelite:1512751559140839576>"
  );
  return next;
}

function syncLiveConfig(data = {}) {
  try {
    const migrated = applySafeEmbedDisplayMigrations(data);
    for (const key of Object.keys(config)) delete config[key];
    Object.assign(config, migrated);
  } catch (err) {
    console.log("SYNC CONFIG ERROR:", err.message);
  }
}

function writeConfigFile(data) {
  const configPath = getDashboardConfigPath();
  const migrated = applySafeEmbedDisplayMigrations(data);
  fs.writeFileSync(configPath, JSON.stringify(migrated, null, 2), "utf8");
  syncLiveConfig(migrated);
  console.log(`✅ Dashboard config saved + live reloaded: ${configPath}`);
}

function escapeHtml(input = "") {
  return String(input)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}


// Discord tidak merender custom animated emoji jika ditulis sebagai teks di embed footer.
// Solusi aman: footer text tetap rapi, emoji DESA TULUS dipasang sebagai footer icon dari CDN emoji Discord.
const OT_FOOTER_EMOJI = "<a:Desa_Tulus:1516424353934348299>";
const OT_FOOTER_EMOJI_ID = "1516424353934348299";
const OT_FOOTER_ICON_URL = `https://cdn.discordapp.com/emojis/${OT_FOOTER_EMOJI_ID}.gif?size=44&quality=lossless`;
const OT_FOOTER_PREFIX = "DESA TULUS";

// Normalisasi shortcode emoji lama agar selalu menjadi custom emoji Discord asli.
// Bentuk :nama: tidak akan tampil sebagai GIF tanpa ID emoji, jadi Pak RW mengubah
// shortcode yang dikenal sebelum dikirim ke Discord dan sebelum ditampilkan di preview.
const PAK_RW_KNOWN_EMOJI_CODES = Object.freeze({
  rocket_animated: "<a:rocket_animated:1512884173453529288>",
  bar_chart: "<a:bar_chart:1516453838117277829>",
  Chart_Increasing: "<a:Chart_Increasing:1516454160684290219>",
  Animated_Arrow_Bluelite: "<a:Animated_Arrow_Bluelite:1512751559140839576>",
  Desa_Tulus: "<a:Desa_Tulus:1516424353934348299>"
});

function normalizePakRwEmojiCodes(text = "") {
  let output = String(text || "");
  for (const [name, markup] of Object.entries(PAK_RW_KNOWN_EMOJI_CODES)) {
    // Jangan mengubah markup yang sudah lengkap, karena pada markup lengkap
    // setelah :nama: langsung ada angka ID emoji.
    output = output.replace(new RegExp(`:${name}:(?!\\d)`, "g"), markup);
  }
  return output;
}

// Muat config setelah tabel normalisasi emoji siap agar tidak terkena temporal dead zone.
syncLiveConfig(readConfigFile());

function makeOTFooter(text = "") {
  const raw = String(text || "").trim();
  if (!raw) return OT_FOOTER_PREFIX;

  let cleaned = raw
    .replaceAll(OT_FOOTER_EMOJI, "")
    .replace(new RegExp(`https://cdn\.discordapp\.com/emojis/${OT_FOOTER_EMOJI_ID}\.[a-z?=&0-9]+`, "gi"), "")
    .replace(/^DESA TULUS\s*[•|\-:]*\s*/i, "")
    .replace(/^Pak RW\s*[•|\-:]*\s*/i, "")
    .replace(/^\{server\}\s*[•|\-:]*\s*/i, "")
    .replace(/^Server\s*[•|\-:]*\s*/i, "")
    .trim();

  if (!cleaned) return OT_FOOTER_PREFIX;
  return `${OT_FOOTER_PREFIX} • ${cleaned}`.slice(0, 2048);
}

function isSafeFooterIconUrl(value = "") {
  return /^https?:\/\//i.test(String(value || "").trim());
}

function makeOTFooterData(text = "", iconURL = "") {
  return {
    text: makeOTFooter(text),
    iconURL: isSafeFooterIconUrl(iconURL) ? String(iconURL).trim() : OT_FOOTER_ICON_URL
  };
}

// Paksa semua embed footer Pak RW punya icon emoji DESA TULUS yang benar-benar tampil,
// bukan teks mentah <a:desatulus:...> di footer.
try {
  const originalSetFooter = EmbedBuilder.prototype.setFooter;
  if (originalSetFooter && !EmbedBuilder.prototype.__orangTulusFooterPatched) {
    EmbedBuilder.prototype.setFooter = function patchedOrangTulusFooter(options) {
      if (options && typeof options === "object") {
        const rawText = options.text || "";
        const rawIcon = options.iconURL || options.icon_url || "";
        return originalSetFooter.call(this, {
          ...options,
          text: makeOTFooter(rawText),
          iconURL: isSafeFooterIconUrl(rawIcon) ? rawIcon : OT_FOOTER_ICON_URL
        });
      }
      return originalSetFooter.call(this, options);
    };
    EmbedBuilder.prototype.__orangTulusFooterPatched = true;
  }
} catch (err) {
  console.log("OT FOOTER PATCH ERROR:", err?.message || err);
}


