  const num = (value, fallback, min = null, max = null) => {
    let n = Number(value);
    if (!Number.isFinite(n)) n = fallback;
    if (min !== null) n = Math.max(min, n);
    if (max !== null) n = Math.min(max, n);
    return n;
  };
  const bool = (name) => body[name] === "on";
