      <div class="table-wrap"><table><thead><tr><th>#</th><th>User</th><th>Rank Bulan Ini</th><th>Level Bulan Ini</th><th>Poin Bulan Ini</th></tr></thead><tbody>${rowHtml(rows, "active")}</tbody></table></div>
