async function replyDonaturOnly(member, target) {
  if (!isFilledId(config.donaturRoleId)) {
    const msg = "❌ `donaturRoleId` belum diisi di config.json.";
    if (target?.isRepliable?.()) {
      return target.reply({ content: msg, flags: 64 }).catch(() => {});
    }
    return safeReply(target, msg);
  }

  if (!isDonaturMember(member)) {
    const msg = "❌ Command ini khusus untuk member yang punya role Donatur.";
    if (target?.isRepliable?.()) {
      return target.reply({ content: msg, flags: 64 }).catch(() => {});
    }
    return safeReply(target, msg);
  }

  const payload = { embeds: [buildDonaturOnlyEmbed(member)] };

  if (target?.isRepliable?.()) {
    return target.reply({ ...payload, flags: 64 }).catch(() => {});
  }

  return safeReply(target, payload);
}


async function removeDonaturRole(targetMember, channel) {
  if (!targetMember || !targetMember.guild) return false;

  if (!isFilledId(config.donaturRoleId)) {
    await safeSend(channel, "❌ `donaturRoleId` belum diisi di config.json.");
    return false;
  }

  const role = targetMember.guild.roles.cache.get(config.donaturRoleId);
  if (!role) {
    await safeSend(channel, "❌ Role Donatur tidak ditemukan. Cek `donaturRoleId` di config.json.");
    return false;
  }

  if (targetMember.roles.cache.has(role.id)) {
    await targetMember.roles.remove(role).catch((err) => {
      console.log("DONATUR ROLE REMOVE ERROR:", err.message);
    });
  }

  const data = readTempRoles();
  data.roles = (data.roles || []).filter((item) =>
    !(item.guildId === targetMember.guild.id &&
      item.userId === targetMember.id &&
      item.roleId === role.id)
  );
  writeTempRoles(data);

  await safeSend(channel, `✅ Role **${role.name}** berhasil dicabut dari ${targetMember}.`);
  return true;
}



const levelFile = resolvePersistentDataFile("level.json");
const levelCooldown = new Map();
const levelMessageFingerprints = new Map();
const voiceSessions = new Map();
const topActiveDailyPostMemory = new Map();
const topPoinPostStateFile = resolvePersistentDataFile("top-poin-post-state.json");
const boostPoinStateFile = resolvePersistentDataFile("boost-poin-events.json");
const TOP_POIN_AUTO_WINDOW_MINUTES = 10;


function getLevelTuningConfig() {
  const levelCfg = config.level || {};
  return {
    // totalPoints = level dari total poin; chatVoiceSum = level chat + level voice.
    // DESA TULUS sekarang memakai chatVoiceSum supaya alur Chat Lv.10 + Voice Lv.8 = Total Lv.18.
    mode: levelCfg.mode || "chatVoiceSum",
    totalLevelFormula: levelCfg.totalLevelFormula || levelCfg.mode || "chatVoiceSum",
    pointsPerLevel: Math.max(1, Number(levelCfg.pointsPerLevel || 500)),
    chatPointsPerLevel: Math.max(1, Number(levelCfg.chatPointsPerLevel || levelCfg.pointsPerLevel || 500)),
    voicePointsPerLevel: Math.max(1, Number(levelCfg.voicePointsPerLevel || levelCfg.pointsPerLevel || 500)),
    maxLevel: PAK_RW_MAX_LEVEL
  };
}

function getCategoryLevelNumber(points = 0, perLevel = 500) {
  const n = Math.max(0, Number(points || 0));
  const step = Math.max(1, Number(perLevel || 500));
  // 0 poin tidak dihitung sebagai level kategori, supaya total tidak otomatis jadi 2.
  return n > 0 ? Math.floor(n / step) + 1 : 0;
}

function getTotalPointsForLevel(userData = {}) {
  return Number(((Number(userData.chat || 0)) + (Number(userData.voice || 0))).toFixed(1));
}

function getLevelNameByLevel(level = 1) {
  return getLevelTier(level, config).name;
}

function ensureLevelFile() {
  const dir = path.dirname(levelFile);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  if (!fs.existsSync(levelFile)) fs.writeFileSync(levelFile, JSON.stringify({ users: {} }, null, 2));
}

function readLevelData() {
  const mongoData = readStore("level", null);
  if (mongoData) return mongoData;

  try {
    ensureLevelFile();
    return JSON.parse(fs.readFileSync(levelFile, "utf8"));
  } catch {
    return { users: {} };
  }
}

function writeLevelData(data) {
  writeStore("level", data);

  try {
    ensureLevelFile();
    fs.writeFileSync(levelFile, JSON.stringify(data, null, 2));
  } catch (err) {
    console.log("LEVEL WRITE ERROR:", err.message);
  }
}

function getLevelUser(data, guildId, userId) {
  const key = `${guildId}:${userId}`;
  if (!data.users[key]) {
    data.users[key] = {
      guildId,
      userId,
      chat: 0,
      voice: 0,
      level: 1,
      lastMessageAt: 0,
      lifetimeChat: 0,
      lifetimeVoice: 0,
      lifetimeTotal: 0,
      activeCycleCount: 0,
      activeCycleLastResetAt: 0
    };
  }

  const u = data.users[key];
  // Papan Aktif lifetime tidak pernah di-reset. Data lama otomatis dimigrasikan dari chat+voice.
  const currentTotal = Number((Number(u.chat || 0) + Number(u.voice || 0)).toFixed(1));
  if (!Number.isFinite(Number(u.lifetimeTotal)) || Number(u.lifetimeTotal || 0) < currentTotal) {
    u.lifetimeChat = Number(u.chat || 0);
    u.lifetimeVoice = Number(u.voice || 0);
    u.lifetimeTotal = currentTotal;
  }
  u.activeCycleCount = Number(u.activeCycleCount || 0);
  u.level = Math.max(1, Math.min(PAK_RW_MAX_LEVEL, Number(u.level || 1)));
  return u;
}

function getLevelInfo(userData = {}) {
  const tuning = getLevelTuningConfig();
  const total = getTotalPointsForLevel(userData);
  const chatPoints = Math.max(0, Number(userData.chat || 0));
  const voicePoints = Math.max(0, Number(userData.voice || 0));
  const chatLevel = getCategoryLevelNumber(chatPoints, tuning.chatPointsPerLevel);
  const voiceLevel = getCategoryLevelNumber(voicePoints, tuning.voicePointsPerLevel);

  // Alur premium DESA TULUS:
  // Level Chat + Level Voice = Total Level.
  // Contoh: Chat Lv.10 + Voice Lv.8 = Total Lv.18.
  // Poin tetap jelas: Total Poin = Poin Chat + Poin Voice + bonus event/role.
  const formula = tuning.totalLevelFormula || tuning.mode;
  const calculatedLevel = formula === "chatVoiceSum"
    ? Math.max(1, chatLevel + voiceLevel)
    : Math.floor(total / tuning.pointsPerLevel) + 1;
  const level = Math.max(1, Math.min(tuning.maxLevel, calculatedLevel));
  const current = {
    level,
    name: getLevelNameByLevel(level),
    total: Math.max(0, (level - 1) * tuning.pointsPerLevel),
    chat: chatPoints,
    voice: voicePoints,
    chatLevel,
    voiceLevel
  };

  const nextLevel = level < tuning.maxLevel ? level + 1 : null;
  const next = nextLevel
    ? {
        level: nextLevel,
        name: getLevelNameByLevel(nextLevel),
        total: formula === "chatVoiceSum" ? total + Math.min(tuning.chatPointsPerLevel, tuning.voicePointsPerLevel) : (nextLevel - 1) * tuning.pointsPerLevel,
        chat: chatPoints,
        voice: voicePoints
      }
    : null;

  return { current, next, total, tuning };
}

function getLevelInfoFromPoints(points = 0) {
  const tuning = getLevelTuningConfig();
  const total = Math.max(0, Number(points || 0));
  const level = Math.max(1, Math.min(tuning.maxLevel, Math.floor(total / tuning.pointsPerLevel) + 1));
  const current = {
    level,
    name: getLevelNameByLevel(level),
    total: Math.max(0, (level - 1) * tuning.pointsPerLevel),
    chat: 0,
    voice: 0
  };
  const nextLevel = level < tuning.maxLevel ? level + 1 : null;
  const next = nextLevel
    ? {
        level: nextLevel,
        name: getLevelNameByLevel(nextLevel),
        total: (nextLevel - 1) * tuning.pointsPerLevel,
        chat: 0,
        voice: 0
      }
    : null;
  return { current, next, total, tuning };
}

function getLeaderboardPoints(userData = {}, kind = "active") {
  if (kind === "chat") return Number(userData.monthlyChat || 0);
  if (kind === "voice") return Number(userData.monthlyVoice || 0);
  return Number(userData.monthlyTotal || 0);
}

function getLeaderboardLevelInfo(userData = {}, kind = "active") {
  // Leaderboard Top Aktif/Top Chat/Top Voice pakai data BULAN INI.
  // Biar tidak membingungkan, level/rank yang tampil di board juga dihitung dari poin yang sedang ditampilkan.
  return getLevelInfoFromPoints(getLeaderboardPoints(userData, kind));
}

function formatNumber(num) {
  const n = Number(num || 0);
  if (Number.isInteger(n)) return n.toLocaleString("id-ID");
  return n.toLocaleString("id-ID", { minimumFractionDigits: 1, maximumFractionDigits: 1 });
}

async function getOrCreateLevelChannel(guild) {
  if (!guild) return null;

  const levelChannel = getTextChannel(guild, getPakRwLevelSystemConfig().levelChannelId);

  if (!levelChannel) {
    console.log("LEVEL CHANNEL ERROR: levelChannelId belum diisi, salah, atau bot tidak bisa akses channel.");
    return null;
  }

  return levelChannel;
}


function getTotalLevelPoints(userData) {
  // Ini poin siklus level saat ini. Kalau tembus target 100.000, siklus ini di-reset.
  return getTotalPointsForLevel(userData);
}

function getLifetimeLevelPoints(userData = {}) {
  const stored = Number(userData.lifetimeTotal || 0);
  const current = getTotalPointsForLevel(userData);
  return Number(Math.max(stored, current).toFixed(1));
}

function addLifetimeLevelPoints(userData, type, amount) {
  const value = normalizeLevelPointAmount(amount);
  if (!value) return;
  if (type === "chat") userData.lifetimeChat = Number((Number(userData.lifetimeChat || 0) + value).toFixed(1));
  if (type === "voice") userData.lifetimeVoice = Number((Number(userData.lifetimeVoice || 0) + value).toFixed(1));
  userData.lifetimeTotal = Number((Number(userData.lifetimeChat || 0) + Number(userData.lifetimeVoice || 0)).toFixed(1));
  userData.lifetimeLastActivityAt = Date.now();
}

function getLevelCycleThreshold() {
  const cfg = getTopActiveConfig();
  return Math.max(1000, Number(cfg.pointsThreshold || 100000));
}

function resetUserLevelCycleAfterTarget(userData, type, threshold) {
  const current = getTotalPointsForLevel(userData);
  if (current < threshold) return false;

  const remainder = Number(Math.max(0, current - threshold).toFixed(1));
  // Siklus level diulang dari awal; Papan Aktif lifetime tetap menyimpan total lama + baru.
  userData.chat = 0;
  userData.voice = 0;
  if (type === "voice") userData.voice = remainder;
  else userData.chat = remainder;
  userData.level = getLevelInfo(userData).current.level;
  userData.activeCycleCount = Number(userData.activeCycleCount || 0) + 1;
  userData.activeCycleLastResetAt = Date.now();
  userData.lastMotmThreshold = threshold;
  return true;
}

function isServerOwnerId(guildOrOwnerId, userId) {
  const ownerId = typeof guildOrOwnerId === "string" ? guildOrOwnerId : guildOrOwnerId?.ownerId;
  return Boolean(ownerId && userId && String(ownerId) === String(userId));
}

function shouldExcludeOwnerFromLevel(guildOrOwnerId, userId) {
  const levelCfg = config.level || {};
  const topCfg = config.topActive || {};
  const enabled = levelCfg.excludeOwnerFromLevel !== false && topCfg.excludeOwnerFromLevel !== false;
  return Boolean(enabled && isServerOwnerId(guildOrOwnerId, userId));
}

function shouldExcludeOwnerFromLeaderboard(guildOrOwnerId, userId) {
  const topCfg = config.topActive || {};
  const enabled = topCfg.excludeOwnerFromLeaderboard !== false;
  return Boolean(enabled && isServerOwnerId(guildOrOwnerId, userId));
}

function removeOwnerLevelData(guild) {
  try {
    if (!guild?.ownerId) return false;
    const data = readLevelData();
    let changed = false;
    for (const [key, userData] of Object.entries(data.users || {})) {
      if (userData.guildId === guild.id && userData.userId === guild.ownerId) {
        delete data.users[key];
        changed = true;
      }
    }
    if (changed) {
      writeLevelData(data);
      console.log(`✅ Owner dikecualikan dari level/leaderboard: data owner dibersihkan di ${guild.name}`);
    }
    return changed;
  } catch (err) {
    console.log("OWNER LEVEL CLEAN ERROR:", err.message);
    return false;
  }
}
async function syncAllLevelsWithPoints(guild) {
  if (guild?.id) createLevelRoleBackup(guild.id);
  const data = readLevelData();
  let changed = 0;
  for (const userData of Object.values(data.users || {})) {
    if (guild?.id && userData.guildId !== guild.id) continue;
    if (guild?.ownerId && shouldExcludeOwnerFromLevel(guild, userData.userId)) continue;
    const correctLevel = getLevelInfo(userData).current.level;
    if (Number(userData.level || 1) !== correctLevel) {
      userData.level = correctLevel;
      changed++;
    }
  }
  if (changed > 0) writeLevelData(data);
  const roleSync = guild ? await syncAllMemberLevelRoles(guild, { batchSize: 5, delayMs: 900 }) : null;
  return {
    changed,
    total: Object.values(data.users || {}).filter((u) => !guild?.id || u.guildId === guild.id).length,
    roleSync
  };
}


function getPakRwLevelRoleTier(level = 1) {
  return getLevelTier(level, config);
}

function getPakRwLevelRoleTiers() {
  return getLevelRoleTiers(config);
}

function getPakRwLevelSystemConfig() {
  return getLevelSystemConfig(config);
}

function getLevelRoleMention(level = 1) {
  const tier = getPakRwLevelRoleTier(level);
  return tier?.roleId ? `<@&${tier.roleId}>` : "Belum dikonfigurasi";
}

function getMemberConfiguredLevelRoleIds(member) {
  if (!member?.roles?.cache) return [];
  const configured = new Set(getConfiguredLevelRoleIds(config));
  return [...member.roles.cache.keys()].filter((roleId) => configured.has(roleId));
}

function getLevelRoleSyncStatus(member, level) {
  const tier = getPakRwLevelRoleTier(level);
  const currentRoleIds = getMemberConfiguredLevelRoleIds(member);
  const correct = Boolean(tier?.roleId)
    && currentRoleIds.length === 1
    && currentRoleIds[0] === tier.roleId;
  return { tier, currentRoleIds, correct };
}

const levelRoleWarningTimes = new Map();
function logLevelRoleWarningOnce(key, message, ttlMs = 30 * 60 * 1000) {
  const now = Date.now();
  const last = Number(levelRoleWarningTimes.get(key) || 0);
  if (now - last < ttlMs) return;
  levelRoleWarningTimes.set(key, now);
  console.log(message);
}

async function syncMemberLevelRole(member, level, options = {}) {
  const system = getPakRwLevelSystemConfig();
  const safeLevel = Math.max(1, Math.min(PAK_RW_MAX_LEVEL, Number(level) || 1));
  const tier = getPakRwLevelRoleTier(safeLevel);

  if (!system.enabled) {
    return { success: false, skipped: true, reason: "LEVEL_SYSTEM_DISABLED", tier };
  }
  if (!system.autoLevelRole) {
    return { success: false, skipped: true, reason: "AUTO_LEVEL_ROLE_DISABLED", tier };
  }
  if (!member?.guild || !member?.roles?.cache || member.user?.bot) {
    return { success: false, skipped: true, reason: "INVALID_MEMBER", tier };
  }
  if (!tier?.roleId) {
    if (!options.silent) console.log(`[LEVEL ROLE] ${tier?.name || "Tier"} belum memiliki Role ID.`);
    return { success: false, reason: "ROLE_TIER_NOT_CONFIGURED", tier };
  }

  const guild = member.guild;
  const botMember = guild.members.me || await guild.members.fetchMe().catch(() => null);
  const targetRole = guild.roles.cache.get(tier.roleId) || await guild.roles.fetch(tier.roleId).catch(() => null);
  if (!targetRole) {
    console.log(`[LEVEL ROLE] ERROR: Role ${tier.name} (${tier.roleId}) tidak ditemukan.`);
    return { success: false, reason: "ROLE_NOT_FOUND", tier };
  }
  if (targetRole.managed) {
    console.log(`[LEVEL ROLE] ERROR: Role ${tier.name} dikelola integrasi dan tidak dapat diberikan manual.`);
    return { success: false, reason: "ROLE_MANAGED", tier };
  }
  if (!botMember?.permissions?.has(PermissionsBitField.Flags.ManageRoles)) {
    console.log("[LEVEL ROLE] ERROR: Pak RW tidak memiliki permission Manage Roles.");
    return { success: false, reason: "MISSING_MANAGE_ROLES", tier };
  }
  if (botMember.roles.highest.comparePositionTo(targetRole) <= 0) {
    console.log(`[LEVEL ROLE] ERROR: Role ${tier.name} berada setara/di atas role Pak RW.`);
    return { success: false, reason: "ROLE_HIERARCHY", tier };
  }
  if (member.id === guild.ownerId || botMember.roles.highest.comparePositionTo(member.roles.highest) <= 0) {
    logLevelRoleWarningOnce(`member-hierarchy:${guild.id}:${member.id}`, `[LEVEL ROLE] SKIP: Pak RW tidak dapat mengelola role member ${member.user.tag} karena hierarchy member.`);
    return { success: false, reason: "MEMBER_HIERARCHY", tier };
  }

  const configuredRoleIds = getConfiguredLevelRoleIds(config);
  const oldRoleIds = configuredRoleIds.filter((roleId) => roleId !== tier.roleId && member.roles.cache.has(roleId));
  const reason = `Sinkronisasi role level Pak RW: Level ${safeLevel} • ${tier.name}`;

  try {
    if (oldRoleIds.length) await member.roles.remove(oldRoleIds, reason);
    if (!member.roles.cache.has(tier.roleId)) await member.roles.add(tier.roleId, reason);
    if (!options.silent) {
      console.log(`[LEVEL ROLE] ${member.user.tag} → ${tier.name} (Level ${safeLevel}).`);
    }
    return { success: true, tier, removedRoleIds: oldRoleIds };
  } catch (error) {
    console.error("[LEVEL ROLE] Gagal sinkronisasi role:", {
      guildId: guild.id,
      userId: member.id,
      level: safeLevel,
      tier: tier.name,
      error: error?.message || error
    });
    return { success: false, reason: "ROLE_UPDATE_FAILED", error, tier };
  }
}

function createLevelRoleBackup(guildId = "all") {
  const data = readLevelData();
  const backupDir = path.join(__dirname, "backups");
  fs.mkdirSync(backupDir, { recursive: true });
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  const filename = path.join(backupDir, `level-role-before-sync-${guildId}-${stamp}.json`);
  fs.writeFileSync(filename, JSON.stringify({ createdAt: new Date().toISOString(), guildId, data }, null, 2));
  return filename;
}

function waitLevelRoleBatch(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function syncAllMemberLevelRoles(guild, options = {}) {
  const batchSize = Math.max(1, Math.min(10, Number(options.batchSize || 5)));
  const delayMs = Math.max(250, Math.min(5000, Number(options.delayMs || 900)));
  const data = readLevelData();
  const users = Object.values(data.users || {}).filter((item) => item.guildId === guild.id);
  const result = { total: users.length, synced: 0, skipped: 0, failed: 0, missingMembers: 0 };

  for (let index = 0; index < users.length; index += batchSize) {
    const batch = users.slice(index, index + batchSize);
    for (const userData of batch) {
      if (shouldExcludeOwnerFromLevel(guild, userData.userId)) {
        result.skipped += 1;
        continue;
      }
      const member = guild.members.cache.get(userData.userId)
        || await guild.members.fetch(userData.userId).catch(() => null);
      if (!member) {
        result.missingMembers += 1;
        continue;
      }
      const level = getLevelInfo(userData).current.level;
      const sync = await syncMemberLevelRole(member, level, { silent: true });
      if (sync.success) result.synced += 1;
      else if (sync.skipped) result.skipped += 1;
      else result.failed += 1;
    }
    if (index + batchSize < users.length) await waitLevelRoleBatch(delayMs);
  }

  return result;
}

let levelRoleConfigSyncTimer = null;

function scheduleLevelRoleSyncAfterConfigChange(guild) {
  if (!guild || !getPakRwLevelSystemConfig().enabled || !getPakRwLevelSystemConfig().autoLevelRole) return;
  if (levelRoleConfigSyncTimer) clearTimeout(levelRoleConfigSyncTimer);
  levelRoleConfigSyncTimer = setTimeout(async () => {
    levelRoleConfigSyncTimer = null;
    const configuredCount = getConfiguredLevelRoleIds(config).length;
    if (configuredCount !== LEVEL_ROLE_TIER_DEFINITIONS.length) {
      console.log(`[LEVEL ROLE] Sinkronisasi otomatis ditunda: baru ${configuredCount}/${LEVEL_ROLE_TIER_DEFINITIONS.length} role tier terisi.`);
      return;
    }
    try {
      createLevelRoleBackup(guild.id);
      const result = await syncAllMemberLevelRoles(guild, { batchSize: 5, delayMs: 900 });
      console.log(`[LEVEL ROLE] Sinkronisasi setelah perubahan config selesai: ${result.synced} berhasil, ${result.failed} gagal.`);
      appendDashboardActivity("level-role", "Role level disinkronkan", `${result.synced} warga berhasil, ${result.failed} gagal.`);
    } catch (error) {
      console.log("[LEVEL ROLE] Sinkronisasi setelah config gagal:", error?.message || error);
    }
  }, 2000);
  if (typeof levelRoleConfigSyncTimer.unref === "function") levelRoleConfigSyncTimer.unref();
}

async function validateLevelRoleSetup(guild) {
  const system = getPakRwLevelSystemConfig();
  if (!guild || !system.enabled) return;
  const botMember = guild.members.me || await guild.members.fetchMe().catch(() => null);
  const canManageRoles = Boolean(botMember?.permissions?.has(PermissionsBitField.Flags.ManageRoles));
  console.log(`[LEVEL ROLE] Auto role: ${system.autoLevelRole ? "aktif" : "nonaktif"} • Max Level ${PAK_RW_MAX_LEVEL}.`);
  console.log(`[LEVEL ROLE] Permission Manage Roles: ${canManageRoles ? "OK" : "TIDAK ADA"}.`);

  for (const tier of getPakRwLevelRoleTiers()) {
    if (!tier.roleId) {
      console.log(`[LEVEL ROLE] BELUM DIATUR: ${tier.name} (Level ${tier.level}).`);
      continue;
    }
    const role = guild.roles.cache.get(tier.roleId) || await guild.roles.fetch(tier.roleId).catch(() => null);
    if (!role) {
      console.log(`[LEVEL ROLE] ERROR: Role ${tier.name} (${tier.roleId}) tidak ditemukan.`);
      continue;
    }
    if (botMember && botMember.roles.highest.comparePositionTo(role) <= 0) {
      console.log(`[LEVEL ROLE] ERROR: Role ${tier.name} berada di atas role Pak RW.`);
    } else {
      console.log(`[LEVEL ROLE] Role ${tier.name} ditemukan.`);
    }
  }

  const levelChannel = getTextChannel(guild, system.levelChannelId);
  if (!levelChannel) {
    console.log("[LEVEL CHANNEL] Channel level belum ditemukan atau belum dikonfigurasi.");
  } else {
    const permissions = levelChannel.permissionsFor(botMember);
    const canSend = Boolean(permissions?.has([
      PermissionsBitField.Flags.ViewChannel,
      PermissionsBitField.Flags.SendMessages,
      PermissionsBitField.Flags.EmbedLinks,
      PermissionsBitField.Flags.ReadMessageHistory
    ]));
    console.log(`[LEVEL CHANNEL] Channel level ditemukan: #${levelChannel.name} • izin ${canSend ? "OK" : "BELUM LENGKAP"}.`);
  }
}

function getServerLevelRank(guildId, userId) {
  const data = readLevelData();
  const rows = Object.values(data.users || {})
    .filter((entry) => entry.guildId === guildId)
    .map((entry) => ({ entry, info: getLevelInfo(entry), total: getTotalPointsForLevel(entry) }))
    .sort((a, b) => b.info.current.level - a.info.current.level || b.total - a.total);
  const index = rows.findIndex((row) => row.entry.userId === userId);
  return index >= 0 ? index + 1 : null;
}

async function handlePakRwLevelRoleCommand(message) {
  if (!message?.guild || !message?.author || message.author.bot) return false;
  const content = String(message.content || "").trim();
  const prefix = String(config.prefix || "rw");
  const lower = content.toLowerCase();
  const aliases = {
    mass: ["paksynclevelroles", `${prefix}synclevelroles`, `${prefix}paksynclevelroles`],
    check: ["pakceklevelrole", `${prefix}ceklevelrole`, `${prefix}pakceklevelrole`],
    one: ["paksynclevelrole", `${prefix}synclevelrole`, `${prefix}paksynclevelrole`]
  };
  const commandType = Object.entries(aliases).find(([, names]) => names.some((name) => lower === name || lower.startsWith(`${name} `)))?.[0];
  if (!commandType) return false;
  if (!isPakRwOwner(message) && !isPakRwStaff(message)) {
    await safeReply(message, "❌ Command sinkronisasi role level hanya untuk owner/staff yang diizinkan.");
    return true;
  }
  if (commandType === "mass" && !isPakRwOwner(message)) {
    await safeReply(message, "❌ Sinkronisasi seluruh server hanya dapat dijalankan owner.");
    return true;
  }

  if (commandType === "mass") {
    const backupFile = createLevelRoleBackup(message.guild.id);
    await safeReply(message, "⏳ Backup selesai. Sinkronisasi role level seluruh warga dimulai bertahap agar aman dari rate limit.");
    const result = await syncAllMemberLevelRoles(message.guild, { batchSize: 5, delayMs: 900 });
    await safeSend(message.channel, {
      embeds: [new EmbedBuilder()
        .setColor(DESA_TULUS_EMBED_COLOR_INT)
        .setTitle("Sinkronisasi Role Level Selesai")
        .setDescription([
          `Data diperiksa: **${formatNumber(result.total)} warga**`,
          `Berhasil disinkronkan: **${formatNumber(result.synced)}**`,
          `Dilewati: **${formatNumber(result.skipped)}**`,
          `Member tidak ada di server: **${formatNumber(result.missingMembers)}**`,
          `Gagal: **${formatNumber(result.failed)}**`,
          "",
          `Backup lokal: \`${path.basename(backupFile)}\``
        ].join("\n"))
        .setFooter({ text: makeOTFooter("DESA TULUS • Auto Level Role") })
        .setTimestamp()]
    });
    return true;
  }

  const target = message.mentions.members.first() || message.member;
  const data = readLevelData();
  const userData = getLevelUser(data, message.guild.id, target.id);
  const info = getLevelInfo(userData);
  const status = getLevelRoleSyncStatus(target, info.current.level);
  const expectedRole = status.tier.roleId ? `<@&${status.tier.roleId}>` : "Belum dikonfigurasi";
  const currentRoles = status.currentRoleIds.length ? status.currentRoleIds.map((id) => `<@&${id}>`).join(", ") : "Tidak ada";

  if (commandType === "one") {
    const sync = await syncMemberLevelRole(target, info.current.level);
    await safeReply(message, sync.success
      ? `✅ Role level ${target} sudah disinkronkan menjadi **${status.tier.name}** tanpa mengubah EXP atau level.`
      : `❌ Sinkronisasi gagal: **${sync.reason || "UNKNOWN"}**. Cek log Pak RW dan posisi role.`);
    return true;
  }

  await safeReply(message, {
    embeds: [new EmbedBuilder()
      .setColor(DESA_TULUS_EMBED_COLOR_INT)
      .setTitle("Pemeriksaan Role Level Warga")
      .setDescription(`${target}`)
      .addFields(
        { name: "Level tersimpan", value: String(info.current.level), inline: true },
        { name: "Tingkatan seharusnya", value: status.tier.name, inline: true },
        { name: "Status", value: status.correct ? "Sesuai" : "Belum sesuai", inline: true },
        { name: "Role seharusnya", value: expectedRole, inline: false },
        { name: "Role level saat ini", value: currentRoles, inline: false }
      )
      .setFooter({ text: makeOTFooter("DESA TULUS • Pemeriksaan Auto Level Role") })
      .setTimestamp()]
  });
  return true;
}

function memberHasRole(member, roleId) {
  return Boolean(member && isFilledId(roleId) && member.roles?.cache?.has(roleId));
}

function getLevelBonusInfo(member) {
  const cfg = getTopActiveConfig();
  const percent = Math.max(0, Number(cfg.bonusPercent ?? 15));
  const sources = [];

  if (member?.premiumSince) sources.push("Server Booster");
  if (memberHasRole(member, config.juragan?.roleId)) sources.push("Role Juragan");
  if (memberHasRole(member, config.donaturRoleId)) sources.push("Role Donatur");

  const active = Boolean(cfg.bonusEnabled && percent > 0 && sources.length);
  return {
    enabled: cfg.bonusEnabled !== false,
    active,
    percent,
    multiplier: active ? Number((1 + percent / 100).toFixed(4)) : 1,
    sources,
    sourceText: sources.length ? sources.join(" + ") : "Belum ada role bonus"
  };
}

function calculateLevelBonus(member, baseAmount) {
  const base = Number(baseAmount || 0);
  const info = getLevelBonusInfo(member);
  const bonus = info.active ? Number((base * (info.percent / 100)).toFixed(1)) : 0;
  return {
    ...info,
    baseAmount: base,
    bonusAmount: bonus,
    totalAmount: Number((base + bonus).toFixed(1))
  };
}


function getBoostPoinConfig() {
  const raw = config.boostPoin || {};
  const channelId = parseDiscordId(raw.channelId || "");
  const primaryChatId = parseDiscordId(raw.chatChannelId || "");
  const primaryVoiceId = parseDiscordId(raw.voiceChannelId || "");
  const chatChannelIds = [
    primaryChatId,
    ...(Array.isArray(raw.chatChannelIds) ? raw.chatChannelIds.map(parseDiscordId) : [])
  ].filter(Boolean);
  const voiceChannelIds = [
    primaryVoiceId,
    ...(Array.isArray(raw.voiceChannelIds) ? raw.voiceChannelIds.map(parseDiscordId) : [])
  ].filter(Boolean);
  const legacyPercent = Math.max(0, Number(raw.boostPercent ?? 5));
  const multiplier = Math.max(1, Math.min(100, Number(raw.multiplier ?? (1 + legacyPercent / 100)) || 1));
  const boostPercent = Number(((multiplier - 1) * 100).toFixed(4));
  return {
    enabled: raw.enabled !== false,
    eventActive: raw.eventActive === true,
    eventId: String(raw.eventId || getJakartaMonthKey(new Date()).replace("-", "") + "-boost").trim(),
    eventName: String(raw.eventName || "Boost Poin DESA TULUS").trim(),
    eventMode: ["chat", "voice", "chat_voice"].includes(raw.eventMode) ? raw.eventMode : "chat_voice",
    multiplier,
    boostPercent,
    durationMinutes: Math.max(1, Number(raw.durationMinutes || 60)),
    startedAt: Math.max(0, Number(raw.startedAt || 0)),
    endsAt: Math.max(0, Number(raw.endsAt || 0)),
    eventByText: String(raw.eventByText || raw.eventBy || config.ownerName || "Pak RW").trim(),
    eventByUserId: parseDiscordId(raw.eventByUserId || ""),
    channelId,
    channelName: String(raw.channelName || "boost-poin").trim(),
    chatChannelIds: [...new Set(chatChannelIds.length ? chatChannelIds : (channelId ? [channelId] : []))],
    voiceChannelIds: [...new Set(voiceChannelIds)],
    includeAllChatChannels: raw.includeAllChatChannels === true,
    includeAllVoiceChannels: raw.includeAllVoiceChannels === true,
    autoRegisterParticipants: raw.autoRegisterParticipants !== false,
    autoEndEnabled: raw.autoEndEnabled !== false,
    announceOnStart: raw.announceOnStart !== false,
    announceOnEnd: raw.announceOnEnd !== false,
    logToConsole: raw.logToConsole !== false,
    sendNotice: raw.sendNotice === true,
    status: raw.eventActive === true ? "Aktif" : "Nonaktif"
  };
}

function readBoostPoinState() {
  try {
    const dir = path.dirname(boostPoinStateFile);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    if (!fs.existsSync(boostPoinStateFile)) fs.writeFileSync(boostPoinStateFile, JSON.stringify({ events: {} }, null, 2), "utf8");
    const parsed = JSON.parse(fs.readFileSync(boostPoinStateFile, "utf8"));
    if (!parsed.events || typeof parsed.events !== "object") parsed.events = {};
    return parsed;
  } catch (err) {
    console.log("BOOST POIN STATE READ ERROR:", err?.message || err);
    return { events: {} };
  }
}

function writeBoostPoinState(state = { events: {} }) {
  try {
    const dir = path.dirname(boostPoinStateFile);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(boostPoinStateFile, JSON.stringify(state, null, 2), "utf8");
    return true;
  } catch (err) {
    console.log("BOOST POIN STATE WRITE ERROR:", err?.message || err);
    return false;
  }
}

function isBoostPoinTypeAllowed(type, cfg = getBoostPoinConfig()) {
  if (cfg.eventMode === "chat") return type === "chat";
  if (cfg.eventMode === "voice") return type === "voice";
  return type === "chat" || type === "voice";
}

function isBoostPoinChannelAllowed(type, channelId, cfg = getBoostPoinConfig()) {
  const id = parseDiscordId(channelId || "");
  if (!id) return false;
  if (type === "chat") return cfg.includeAllChatChannels || cfg.chatChannelIds.includes(id);
  if (type === "voice") return cfg.includeAllVoiceChannels || cfg.voiceChannelIds.includes(id);
  return false;
}

function registerBoostPoinParticipant(member, type, sourceChannelId, baseAmount, boostAmount) {
  const cfg = getBoostPoinConfig();
  if (!cfg.autoRegisterParticipants || !member?.guild) return;
  const state = readBoostPoinState();
  const eventId = cfg.eventId || "boost-event";
  state.events[eventId] = state.events[eventId] || {
    eventId,
    eventName: cfg.eventName,
    mode: cfg.eventMode,
    boostPercent: cfg.boostPercent,
    createdAt: Date.now(),
    updatedAt: Date.now(),
    participants: {}
  };
  const ev = state.events[eventId];
  ev.eventName = cfg.eventName;
  ev.mode = cfg.eventMode;
  ev.boostPercent = cfg.boostPercent;
  ev.updatedAt = Date.now();
  ev.participants[member.id] = ev.participants[member.id] || {
    userId: member.id,
    username: member.user?.username || "Unknown",
    displayName: member.displayName || member.user?.username || "Unknown",
    chatCount: 0,
    voiceMinutes: 0,
    basePoints: 0,
    boostPoints: 0,
    totalAwarded: 0,
    firstAt: Date.now(),
    lastAt: Date.now(),
    channels: []
  };
  const p = ev.participants[member.id];
  if (type === "chat") p.chatCount = Number(p.chatCount || 0) + 1;
  if (type === "voice") p.voiceMinutes = Number((Number(p.voiceMinutes || 0) + (Number(baseAmount || 0) / Math.max(0.1, getLevelVoicePointPerMinute()))).toFixed(2));
  p.basePoints = Number((Number(p.basePoints || 0) + Number(baseAmount || 0)).toFixed(1));
  p.boostPoints = Number((Number(p.boostPoints || 0) + Number(boostAmount || 0)).toFixed(1));
  p.totalAwarded = Number((Number(p.totalAwarded || 0) + Number(baseAmount || 0) + Number(boostAmount || 0)).toFixed(1));
  p.lastAt = Date.now();
  if (sourceChannelId && !p.channels.includes(String(sourceChannelId))) p.channels.push(String(sourceChannelId));
  writeBoostPoinState(state);
}

function getBoostPoinBonusInfo(member, type, baseAmount, sourceChannelId) {
  const cfg = getBoostPoinConfig();
  const base = Number(baseAmount || 0);
  if (!cfg.enabled || !cfg.eventActive || cfg.multiplier <= 1 || base <= 0) {
    return { active: false, multiplier: cfg.multiplier, percent: cfg.boostPercent, bonusAmount: 0, sourceText: "Boost Poin nonaktif" };
  }
  if (!isBoostPoinTypeAllowed(type, cfg) || !isBoostPoinChannelAllowed(type, sourceChannelId, cfg)) {
    return { active: false, multiplier: cfg.multiplier, percent: cfg.boostPercent, bonusAmount: 0, sourceText: "Aktivitas bukan channel event" };
  }
  const bonus = Number((base * (cfg.multiplier - 1)).toFixed(1));
  registerBoostPoinParticipant(member, type, sourceChannelId, base, bonus);
  if (cfg.logToConsole) console.log(`⚡ BOOST POIN x${formatNumber(cfg.multiplier)}: ${member.user?.tag || member.id} ${type} +${bonus} poin (${cfg.eventName})`);
  return { active: true, multiplier: cfg.multiplier, percent: cfg.boostPercent, bonusAmount: bonus, sourceText: `Event ${cfg.eventName}` };
}

function getBoostPoinMultiplierText(multiplier = getBoostPoinConfig().multiplier) {
  const value = Math.max(1, Number(multiplier || 1));
  return `x${formatNumber(value)}`;
}

function getBoostPoinModeText(mode = "chat_voice") {
  if (mode === "chat") return "chat";
  if (mode === "voice") return "voice";
  return "chat dan voice";
}

function mentionListFromIds(ids = [], type = "role") {
  const safeIds = (Array.isArray(ids) ? ids : [])
    .map((id) => parseDiscordId(id))
    .filter(Boolean)
    .slice(0, 8);
  if (!safeIds.length) return "";
  if (type === "channel") return safeIds.map((id) => `<#${id}>`).join(" ");
  return safeIds.map((id) => `<@&${id}>`).join(" ");
}

function getBoostPoinByText(cfg = getBoostPoinConfig()) {
  if (cfg.eventByUserId) return `<@${cfg.eventByUserId}>`;
  const raw = String(cfg.eventByText || config.ownerName || "PAK RW").trim();
  if (!raw) return config.ownerName || "PAK RW";
  const id = parseDiscordId(raw);
  if (id && raw.includes("@")) return `<@${id}>`;
  return raw;
}

function getBoostPoinEndsAtText(cfg = getBoostPoinConfig()) {
  const duration = Math.max(1, Number(cfg.durationMinutes || 60));
  const endAt = Number(cfg.endsAt || 0) > 0 ? Number(cfg.endsAt) : (Date.now() + duration * 60 * 1000);
  return `<t:${Math.floor(endAt / 1000)}:R>`;
}

function getBoostPoinTargetChannelsText(cfg = getBoostPoinConfig()) {
  const rows = [];
  if (cfg.eventMode !== "voice") {
    rows.push(cfg.includeAllChatChannels ? "Semua channel chat" : (mentionListFromIds(cfg.chatChannelIds, "channel") || "Channel chat belum diatur"));
  }
  if (cfg.eventMode !== "chat") {
    rows.push(cfg.includeAllVoiceChannels ? "Semua voice channel" : (mentionListFromIds(cfg.voiceChannelIds, "channel") || "Voice channel belum diatur"));
  }
  return rows.join("\n") || "Channel event belum diatur";
}

function getBoostPoinAnnouncementConfig() {
  const raw = config.boostPoin || {};
  const cfg = getBoostPoinConfig();
  return {
    title: String(raw.announcementTitle || "<a:Boost:1512485430887714866> BOOST POIN DIAKTIFKAN").trim(),
    description: String(raw.announcementDescription || "Boost poin dimulai:\n\n👤 Oleh: {by}\n💥 Multiplier: {multiplier}\n⏱️ Durasi: {duration} menit\n📍 Channel: {channels}\n🕒 Berakhir: {endsAt}").trim(),
    endTitle: String(raw.endTitle || "<a:Boost:1512485430887714866> BOOST POIN BERAKHIR").trim(),
    endDescription: String(raw.endDescription || "Boost poin untuk channel {channels} telah selesai.\n\n🔄 Status: Kembali ke normal (x1)").trim(),
    mentionText: String(raw.mentionText || "").trim(),
    roleMentionIds: Array.isArray(raw.roleMentionIds) ? raw.roleMentionIds.map(parseDiscordId).filter(Boolean) : [],
    color: String(raw.announcementColor || "#34D399").trim(),
    endColor: DESA_TULUS_EMBED_COLOR_HEX,
    showJoinButton: raw.showJoinButton === true,
    joinButtonLabel: String(raw.joinButtonLabel || "Buka Channel Event").trim(),
    multiplier: cfg.multiplier
  };
}

function applyBoostPoinTemplate(text = "", guild = null) {
  const cfg = getBoostPoinConfig();
  const data = {
    server: config.serverName || guild?.name || "DESA TULUS",
    eventName: cfg.eventName,
    eventId: cfg.eventId,
    boostPercent: formatNumber(cfg.boostPercent),
    multiplier: getBoostPoinMultiplierText(cfg.multiplier),
    mode: getBoostPoinModeText(cfg.eventMode),
    channels: getBoostPoinTargetChannelsText(cfg),
    by: getBoostPoinByText(cfg),
    duration: formatNumber(cfg.durationMinutes || 60),
    endsAt: getBoostPoinEndsAtText(cfg),
    status: cfg.eventActive ? "Aktif" : "Nonaktif"
  };
  return String(text || "")
    .replaceAll("{server}", data.server)
    .replaceAll("{eventName}", data.eventName)
    .replaceAll("{eventId}", data.eventId)
    .replaceAll("{boostPercent}", data.boostPercent)
    .replaceAll("{multiplier}", data.multiplier)
    .replaceAll("{mode}", data.mode)
    .replaceAll("{channels}", data.channels)
    .replaceAll("{by}", data.by)
    .replaceAll("{duration}", data.duration)
    .replaceAll("{endsAt}", data.endsAt)
    .replaceAll("{status}", data.status);
}

function buildBoostPoinPublicPayload(guild, state = "active") {
  const cfg = getBoostPoinConfig();
  const ac = getBoostPoinAnnouncementConfig();
  const isEnd = state === "end";
  const template = embedCfg(isEnd ? "boostPoinEnd" : "boostPoinActive");
  const fallbackTitle = isEnd ? ac.endTitle : ac.title;
  const fallbackDescription = isEnd ? ac.endDescription : ac.description;
  const title = applyBoostPoinTemplate(template.title || fallbackTitle, guild);
  const description = applyBoostPoinTemplate(template.description || fallbackDescription, guild);
  const roleMentions = mentionListFromIds(ac.roleMentionIds, "role");
  const contentParts = [];
  const templateContent = applyBoostPoinTemplate(template.content || "", guild).trim();
  if (templateContent) contentParts.push(templateContent);
  if (!isEnd && ac.mentionText) contentParts.push(applyBoostPoinTemplate(ac.mentionText, guild));
  if (!isEnd && roleMentions) contentParts.push(roleMentions);

  const embed = new EmbedBuilder()
    .setColor(DESA_TULUS_EMBED_COLOR_INT)
    .setTitle(title)
    .setDescription(description)
    .setFooter({ text: makeOTFooter(template.footer || "DESA TULUS • Boost Poin"), iconURL: template.footerIcon || OT_FOOTER_ICON_URL })
    .setTimestamp();

  const authorName = applyBoostPoinTemplate(template.authorName || "DESA TULUS • Boost Poin", guild);
  if (authorName) embed.setAuthor({ name: authorName, iconURL: dashboardSafeUrl(template.authorIcon) || undefined });
  if (Array.isArray(template.fields) && template.fields.length) {
    embed.addFields(template.fields.slice(0, 25).map((field) => ({
      name: applyBoostPoinTemplate(field.name || "Info", guild).slice(0, 256),
      value: applyBoostPoinTemplate(field.value || "-", guild).slice(0, 1024),
      inline: Boolean(field.inline)
    })));
  }
  const image = dashboardSafeUrl(template.image || template.imageUrl || "");
  const thumbnail = dashboardSafeUrl(template.thumbnail || template.thumbnailUrl || "");
  if (image) embed.setImage(image);
  if (thumbnail) embed.setThumbnail(thumbnail);

  const payload = { content: contentParts.join("\n") || undefined, embeds: [embed] };

  if (!isEnd && ac.showJoinButton && guild) {
    const firstVoiceId = cfg.voiceChannelIds?.[0] || "";
    const firstChatId = cfg.chatChannelIds?.[0] || cfg.channelId || "";
    const targetId = firstVoiceId || firstChatId;
    if (targetId) {
      payload.components = [new ActionRowBuilder().addComponents(
        new ButtonBuilder()
          .setLabel(ac.joinButtonLabel || "Buka Channel Event")
          .setStyle(ButtonStyle.Link)
          .setURL(`https://discord.com/channels/${guild.id}/${targetId}`)
      )];
    }
  }

  return payload;
}

async function sendBoostPoinPublicPost(guild, state = "active") {
  const cfg = getBoostPoinConfig();
  if (!guild) return { ok: false, message: "Bot belum membaca server Discord." };
  if (!cfg.channelId) return { ok: false, message: "Channel Boost Poin belum diatur." };
  const channel = getTextChannel(guild, cfg.channelId);
  if (!channel) return { ok: false, message: `Channel Boost Poin tidak ditemukan atau bot tidak punya akses. ID: ${cfg.channelId}` };

  try {
    const me = guild.members.me || await guild.members.fetchMe().catch(() => null);
    const perms = me && channel.permissionsFor ? channel.permissionsFor(me) : null;
    if (perms && (!perms.has(PermissionsBitField.Flags.ViewChannel) || !perms.has(PermissionsBitField.Flags.SendMessages) || !perms.has(PermissionsBitField.Flags.EmbedLinks))) {
      return { ok: false, message: "Permission kurang di channel Boost Poin. Wajib: View Channel, Send Messages, Embed Links." };
    }
  } catch (err) {
    console.log("BOOST POIN PERMISSION CHECK WARNING:", err?.message || err);
  }

  console.log(`🚀 BOOST POIN SEND REQUEST: state=${state} channel=#${channel.name} (${channel.id})`);
  const sent = await safeSend(channel, buildBoostPoinPublicPayload(guild, state));
  if (!sent) return { ok: false, message: "Gagal mengirim pengumuman Boost Poin. Cek permission channel dan DisCloud log SAFE SEND ERROR." };
  return { ok: true, message: state === "end" ? `Pengumuman boost berakhir terkirim ke #${channel.name}.` : `Pengumuman boost aktif terkirim ke #${channel.name}.` };
}

let boostPoinAutoEndTimer = null;
let boostPoinAutoEndBusy = false;

function initializeBoostPoinEventState(cfg = getBoostPoinConfig()) {
  const state = readBoostPoinState();
  state.events = state.events || {};
  state.events[cfg.eventId] = state.events[cfg.eventId] || {
    eventId: cfg.eventId,
    eventName: cfg.eventName,
    mode: cfg.eventMode,
    multiplier: cfg.multiplier,
    boostPercent: cfg.boostPercent,
    startedAt: cfg.startedAt || Date.now(),
    endsAt: cfg.endsAt || 0,
    status: cfg.eventActive ? "active" : "ended",
    createdAt: Date.now(),
    updatedAt: Date.now(),
    participants: {}
  };
  const ev = state.events[cfg.eventId];
  ev.eventName = cfg.eventName;
  ev.mode = cfg.eventMode;
  ev.multiplier = cfg.multiplier;
  ev.boostPercent = cfg.boostPercent;
  ev.startedAt = cfg.startedAt || ev.startedAt || Date.now();
  ev.endsAt = cfg.endsAt || ev.endsAt || 0;
  ev.status = cfg.eventActive ? "active" : "ended";
  ev.updatedAt = Date.now();
  writeBoostPoinState(state);
  return ev;
}

async function startBoostPoinEvent(guild, options = {}) {
  const cfgFile = readConfigFile();
  cfgFile.boostPoin = cfgFile.boostPoin || {};
  const bp = cfgFile.boostPoin;
  const now = Date.now();
  const durationMinutes = Math.max(1, Number(bp.durationMinutes || 60));
  const legacyPercent = Math.max(0, Number(bp.boostPercent ?? 5));
  const multiplier = Math.max(1, Math.min(100, Number(bp.multiplier ?? (1 + legacyPercent / 100)) || 1));
  bp.enabled = true;
  bp.eventActive = true;
  bp.multiplier = multiplier;
  bp.boostPercent = Number(((multiplier - 1) * 100).toFixed(4));
  bp.startedAt = now;
  bp.endsAt = now + durationMinutes * 60 * 1000;
  bp.lastStartedAt = now;
  bp.lastEndedAt = 0;
  bp.lastEndReason = "";
  bp.status = "active";
  bp.eventId = `boost-${now}`;
  if (options.actorUserId) bp.eventByUserId = parseDiscordId(options.actorUserId);
  writeConfigFile(cfgFile);
  initializeBoostPoinEventState(getBoostPoinConfig());

  let postResult = { ok: true, message: "Event aktif tanpa pengumuman." };
  if (bp.announceOnStart !== false) postResult = await sendBoostPoinPublicPost(guild, "active");
  appendDashboardActivity("boost", "Boost Poin dimulai", `${getBoostPoinMultiplierText(multiplier)} selama ${durationMinutes} menit.`);
  return {
    ok: true,
    announcementOk: postResult.ok,
    warning: postResult.ok ? "" : postResult.message,
    message: postResult.ok ? `Boost Poin ${getBoostPoinMultiplierText(multiplier)} aktif selama ${durationMinutes} menit. ${postResult.message}` : `Boost Poin ${getBoostPoinMultiplierText(multiplier)} tetap aktif, tetapi embed belum terkirim: ${postResult.message}`,
    config: getBoostPoinConfig()
  };
}

async function stopBoostPoinEvent(guild, options = {}) {
  const cfgBefore = getBoostPoinConfig();
  const cfgFile = readConfigFile();
  cfgFile.boostPoin = cfgFile.boostPoin || {};
  const bp = cfgFile.boostPoin;
  const wasActive = bp.eventActive === true;
  const now = Date.now();
  bp.eventActive = false;
  bp.status = "ended";
  bp.lastEndedAt = now;
  bp.lastEndReason = String(options.reason || "manual");
  bp.endsAt = Number(bp.endsAt || now);
  writeConfigFile(cfgFile);
  initializeBoostPoinEventState({ ...cfgBefore, eventActive: false, endsAt: bp.endsAt });

  let postResult = { ok: true, message: wasActive ? "Event dihentikan tanpa pengumuman." : "Event memang sudah nonaktif." };
  if (wasActive && options.sendAnnouncement !== false && bp.announceOnEnd !== false) postResult = await sendBoostPoinPublicPost(guild, "end");
  appendDashboardActivity("boost", "Boost Poin berakhir", options.reason === "automatic" ? "Durasi event habis dan multiplier kembali ke x1." : "Event dihentikan dari dashboard dan multiplier kembali ke x1.");
  return {
    ok: true,
    announcementOk: postResult.ok,
    warning: postResult.ok ? "" : postResult.message,
    message: postResult.ok
      ? `${wasActive ? "Boost Poin dihentikan" : "Boost Poin sudah nonaktif"}. ${postResult.message}`
      : `Boost Poin sudah dihentikan dan poin kembali x1, tetapi embed akhir belum terkirim: ${postResult.message}`,
    config: getBoostPoinConfig()
  };
}

async function checkBoostPoinAutoEnd() {
  if (boostPoinAutoEndBusy || !client?.isReady?.()) return;
  boostPoinAutoEndBusy = true;
  try {
    const cfg = getBoostPoinConfig();
    if (!cfg.enabled || !cfg.eventActive || cfg.autoEndEnabled === false) return;
    if (!cfg.endsAt) {
      const cfgFile = readConfigFile();
      cfgFile.boostPoin = cfgFile.boostPoin || {};
      cfgFile.boostPoin.startedAt = cfg.startedAt || Date.now();
      cfgFile.boostPoin.endsAt = Date.now() + cfg.durationMinutes * 60 * 1000;
      writeConfigFile(cfgFile);
      return;
    }
    if (Date.now() < cfg.endsAt) return;
    const guild = getDashboardGuild ? getDashboardGuild() : client.guilds.cache.first();
    await stopBoostPoinEvent(guild, { reason: "automatic", sendAnnouncement: true });
  } catch (err) {
    console.log("BOOST POIN AUTO END ERROR:", err?.message || err);
  } finally {
    boostPoinAutoEndBusy = false;
  }
}

function startBoostPoinAutoEndWatcher() {
  if (boostPoinAutoEndTimer) return;
  boostPoinAutoEndTimer = setInterval(checkBoostPoinAutoEnd, 15 * 1000);
  if (typeof boostPoinAutoEndTimer.unref === "function") boostPoinAutoEndTimer.unref();
  checkBoostPoinAutoEnd();
  console.log("⚡ Boost Poin auto-end watcher aktif.");
}

function buildBonusStatusText(member, userData = {}) {
  const info = getLevelBonusInfo(member);
  const last = userData.lastBonusInfo || {};
  const totalBonus = Number(userData.bonusExtraPoints || 0);

  if (!info.enabled) {
    return "Status: **Nonaktif** dari dashboard Top Aktif.";
  }

  if (!info.active) {
    return [
      `Status: **Belum aktif**`,
      `Syarat: punya salah satu dari **Server Booster**, **Role Juragan**, atau **Role Donatur**.`,
      `Bonus yang akan didapat: **+${formatNumber(info.percent)}%** dari poin chat/voice.`
    ].join("\n");
  }

  return [
    `Status: **Aktif +${formatNumber(info.percent)}%**`,
    `Sumber bonus: **${info.sourceText}**`,
    last.bonusAmount ? `Bonus terakhir: **+${formatNumber(last.bonusAmount)}** poin dari **${formatNumber(last.baseAmount)}** poin dasar.` : `Bonus langsung masuk otomatis setiap dapat poin.`,
    `Total bonus terkumpul: **${formatNumber(totalBonus)}** poin.`
  ].join("\n");
}

function progressBar(current, need, size = 12) {
  if (!need || need <= 0) return "▰".repeat(size);
  const ratio = Math.max(0, Math.min(1, current / need));
  const filled = Math.round(ratio * size);
  return "▰".repeat(filled) + "▱".repeat(size - filled);
}

function buildLevelProgressText(userData, next) {
  if (!next) return "🏆 Kamu sudah berada di puncak level DESA TULUS.";

  const totalNow = getTotalPointsForLevel(userData);
  const targetTotal = Number(next.total || 0);
  const totalNeed = Math.max(0, Number((targetTotal - totalNow).toFixed(1)));
  const totalBar = progressBar(Math.max(0, totalNow - Number(next.total || 0) + getLevelTuningConfig().pointsPerLevel), getLevelTuningConfig().pointsPerLevel, 10);

  return [
    `Menuju **Level ${next.level} (${next.name})**`,
    `Butuh: **${formatNumber(totalNeed)} poin lagi**`,
    `Progress: \`${totalBar}\``,
    "",
    `💬 Chat: **${formatNumber(userData.chat || 0)}** poin`,
    `🎙️ Voice: **${formatNumber(userData.voice || 0)}** poin`,
    `⭐ Total: **${formatNumber(totalNow)}** poin`
  ].join("\n");
}

function getCategoryLevelInfo(userData = {}, type = "chat") {
  const tuning = getLevelTuningConfig();
  const levelCfg = config.level || {};
  const perLevel = Math.max(1, Number(
    type === "voice"
      ? (levelCfg.voicePointsPerLevel || levelCfg.pointsPerLevel || tuning.pointsPerLevel)
      : (levelCfg.chatPointsPerLevel || levelCfg.pointsPerLevel || tuning.pointsPerLevel)
  ));
  const points = Math.max(0, Number(userData[type] || 0));
  const level = Math.max(1, Math.min(tuning.maxLevel, Math.floor(points / perLevel) + 1));
  const nextLevel = level < tuning.maxLevel ? level + 1 : null;
  const currentBase = Math.max(0, (level - 1) * perLevel);
  const nextTarget = nextLevel ? (nextLevel - 1) * perLevel : currentBase;
  const need = nextLevel ? Math.max(0, Number((nextTarget - points).toFixed(1))) : 0;
  const progress = nextLevel ? Math.max(0, points - currentBase) : perLevel;
  const percent = nextLevel ? Math.max(0, Math.min(100, Math.round((progress / perLevel) * 100))) : 100;

  return {
    type,
    points,
    level,
    rank: getLevelNameByLevel(level),
    perLevel,
    nextLevel,
    nextRank: nextLevel ? getLevelNameByLevel(nextLevel) : getLevelNameByLevel(level),
    need,
    percent,
    bar: progressBar(progress, perLevel, 10)
  };
}

function buildCekPoinSection(label, emoji, info) {
  if (!info.nextLevel) {
    return [
      `${emoji} **${label}**`,
      `Level: **${info.level}**`,
      `Poin: **${formatNumber(info.points)}**`,
      `Status: **Level maksimal**`,
      `${progressBar(1, 1, 10)} **100%**`
    ].join("\n");
  }

  return [
    `${emoji} **${label}**`,
    `Level: **${info.level}**`,
    `Poin: **${formatNumber(info.points)}**`,
    `Naik Lv.${info.nextLevel}: **${formatNumber(info.need)} poin lagi**`,
    `${info.bar} **${info.percent}%**`
  ].join("\n");
}

function getCekPoinChannelId() {
  return String(config.cekPoinChannelId || config.level?.checkPointChannelId || config.levelChannelId || "").trim();
}

async function getCekPoinChannel(guild) {
  if (!guild) return null;
  const channelId = getCekPoinChannelId();
  if (!isFilledId(channelId)) return null;
  return getTextChannel(guild, channelId);
}

async function sendLevelProfileMessage(message, target, userData) {
  if (!getPakRwLevelSystemConfig().enabled) {
    await safeReply(message, "ℹ️ Sistem level Pak RW sedang dinonaktifkan oleh owner.");
    return false;
  }
  const channel = await getCekPoinChannel(message.guild);
  const payload = {
    content: `${target}`,
    embeds: [buildLevelProfileEmbed(target, userData)]
  };

  if (channel && channel.id !== message.channel.id) {
    await safeSend(channel, payload);
    await safeReply(message, `✅ Cek poin ${target} dikirim ke ${channel}.`);
    return true;
  }

  await safeReply(message, payload);
  return true;
}

async function sendLevelProfileInteraction(interaction, target, userData) {
  if (!getPakRwLevelSystemConfig().enabled) {
    await interaction.reply({ content: "ℹ️ Sistem level Pak RW sedang dinonaktifkan oleh owner.", flags: 64 });
    return false;
  }
  const channel = await getCekPoinChannel(interaction.guild);
  const payload = {
    content: `${target}`,
    embeds: [buildLevelProfileEmbed(target, userData)]
  };

  if (channel && channel.id !== interaction.channelId) {
    await safeSend(channel, payload);
    await interaction.reply({ content: `✅ Cek poin ${target} dikirim ke ${channel}.`, flags: 64 });
    return true;
  }

  await interaction.reply(payload);
  return true;
}

function getLevelBadge(level) {
  const safeLevel = Math.max(1, Math.min(PAK_RW_MAX_LEVEL, Number(level) || 1));
  if (safeLevel >= 1000) return "👑";
  if (safeLevel >= 750) return "🏆";
  if (safeLevel >= 500) return "💎";
  if (safeLevel >= 300) return "⭐";
  if (safeLevel >= 150) return "⚜️";
  if (safeLevel >= 100) return "🛡️";
  if (safeLevel >= 50) return "🔥";
  if (safeLevel >= 30) return "⚡";
  if (safeLevel >= 20) return "🌟";
  if (safeLevel >= 10) return "🚀";
  if (safeLevel >= 5) return "✨";
  return "🌱";
}


function buildLevelUpEmbed(member, userData) {
  const info = getLevelInfo(userData);
  const next = info.next;
  const total = getTotalLevelPoints(userData);
  const chatInfo = getCategoryLevelInfo(userData, "chat");
  const voiceInfo = getCategoryLevelInfo(userData, "voice");
  const e = embedCfg("levelUp");
  const remaining = next ? Math.max(0, Number((next.total - total).toFixed(1))) : 0;
  const data = {
    user: `${member}`,
    username: member.user.username,
    displayName: member.displayName || member.user.username,
    server: config.serverName || "DESA TULUS",
    rank: info.current.name,
    level: info.current.level,
    total: formatNumber(total),
    chat: formatNumber(chatInfo.points),
    voice: formatNumber(voiceInfo.points),
    nextLevel: next?.level || info.current.level,
    nextRank: next?.name || info.current.name,
    remainingPoints: formatNumber(remaining),
    role: getLevelRoleMention(info.current.level),
    levelRole: getLevelRoleMention(info.current.level)
  };

  const fieldName = next
    ? applyTemplate(e.fields?.[0]?.name || "<a:Chart_Increasing:1516454160684290219> Menuju Level {nextLevel} ({nextRank})", data)
    : "🏆 Level Maksimal";
  const fieldValue = next
    ? applyTemplate(e.fields?.[0]?.value || "Butuh:\n**{remainingPoints} poin total lagi**\nChat: **{chat} poin**\nVoice: **{voice} poin**", data)
    : "Kamu sudah mencapai level tertinggi warga DESA TULUS.";

  const embed = new EmbedBuilder()
    .setColor(DESA_TULUS_EMBED_COLOR_INT)
    .setTitle(normalizePakRwEmojiCodes(applyTemplate(e.title || "<a:rocket_animated:1512884173453529288> Warga Naik Level", data)))
    .setDescription(applyTemplate(e.description || "{user} naik menjadi **{rank} — Level {level}**.\n\nTotal poin aktif: **{total} poin**. Tetap rukun dan aktif di desa.", data))
    .addFields(
      { name: "Tingkatan", value: info.current.name, inline: true },
      { name: "Role Level", value: getLevelRoleMention(info.current.level), inline: true },
      { name: normalizePakRwEmojiCodes(fieldName), value: normalizePakRwEmojiCodes(fieldValue), inline: false }
    )
    .setFooter({ text: makeOTFooter(applyTemplate(e.footer || "DESA TULUS • Level Warga", data)), iconURL: e.footerIcon || OT_FOOTER_ICON_URL })
    .setTimestamp();

  return embed;
}

