        const ok = await sendTopActiveBoard(message.guild, `diposting oleh ${message.author.username}`);
        return safeReply(message, ok ? "✅ Papan Top Aktif sudah dikirim." : "❌ Channel Top Aktif belum benar. Cek dashboard `/top-active`.");
